const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
  bold: '\x1b[1m',
};

const CONFIG = {
  // Pipeline configuration
  nodeVersion: process.env.NODE_VERSION || '18',
  environment: process.env.DEPLOY_ENV || 'production',
  deployTarget: process.env.DEPLOY_TARGET || 'remote', // 'remote', 'docker', 'aws', 'local'
  
  // Remote deployment
  remoteHost: process.env.DEPLOY_HOST || 'deploy@production-server.com',
  remotePath: process.env.DEPLOY_PATH || '/var/www/app',
  
  // Docker deployment
  dockerRegistry: process.env.DOCKER_REGISTRY || 'registry.example.com',
  dockerImage: process.env.DOCKER_IMAGE || 'myapp',
  dockerTag: process.env.DOCKER_TAG || 'latest',
  
  // AWS deployment
  awsRegion: process.env.AWS_REGION || 'us-east-1',
  awsS3Bucket: process.env.AWS_S3_BUCKET || 'my-app-deployments',
  awsEbEnvironment: process.env.AWS_EB_ENV || 'my-app-production',
  
  // Build settings
  buildDir: process.env.BUILD_DIR || 'dist',
  testTimeout: process.env.TEST_TIMEOUT || '60000',
  maxRetries: parseInt(process.env.MAX_RETRIES || '3', 10),
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  
  // Caching
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'cicd-cache'),
  enableCache: process.env.ENABLE_CACHE !== 'false',
  
  // Notifications
  slackWebhook: process.env.SLACK_WEBHOOK_URL || '',
  notifyOnSuccess: process.env.NOTIFY_ON_SUCCESS === 'true',
  notifyOnFailure: process.env.NOTIFY_ON_FAILURE !== 'false',
  
  // Rollback
  keepReleases: parseInt(process.env.KEEP_RELEASES || '5', 10),
  enableRollback: process.env.ENABLE_ROLLBACK !== 'false',
  
  // Health check
  healthCheckUrl: process.env.HEALTH_CHECK_URL || 'http://localhost:3000/health',
  healthCheckRetries: parseInt(process.env.HEALTH_CHECK_RETRIES || '10', 10),
  healthCheckInterval: parseInt(process.env.HEALTH_CHECK_INTERVAL || '3000', 10),
};

// Pipeline state
const pipelineState = {
  startTime: Date.now(),
  stages: [],
  currentStage: null,
  errors: [],
  warnings: [],
  artifactPath: null,
  gitCommit: null,
  gitBranch: null,
  version: null,
};

// ============================================================================
// Utility Functions
// ============================================================================

function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStage(stageName) {
  console.log('');
  console.log(`${COLORS.bold}${COLORS.cyan}${'='.repeat(70)}${COLORS.reset}`);
  console.log(`${COLORS.bold}${COLORS.cyan}  STAGE: ${stageName}${COLORS.reset}`);
  console.log(`${COLORS.bold}${COLORS.cyan}${'='.repeat(70)}${COLORS.reset}`);
  console.log('');
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
  pipelineState.warnings.push(message);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const { silent = false, ignoreError = false, retries = 0 } = options;
  
  let lastError;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      if (!silent) {
        log(`$ ${command}`, 'magenta');
      }
      const result = execSync(command, {
        encoding: 'utf-8',
        stdio: silent ? 'pipe' : 'inherit',
        timeout: 300000, // 5 min timeout per command
        env: { ...process.env, FORCE_COLOR: '1' },
        ...options,
      });
      return result;
    } catch (error) {
      lastError = error;
      if (attempt < retries) {
        logWarning(`Command failed (attempt ${attempt + 1}/${retries + 1}), retrying...`);
        execSync('sleep 2');
      }
    }
  }
  
  if (ignoreError) {
    logWarning(`Command failed but ignoreError is set: ${command}`);
    return '';
  }
  throw lastError;
}

function execSilent(command) {
  try {
    return execSync(command, { encoding: 'utf-8', stdio: 'pipe' }).trim();
  } catch {
    return '';
  }
}

function fileExists(filePath) {
  return fs.existsSync(filePath);
}

function readJson(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch {
    return null;
  }
}

function writeJson(filePath, data) {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
}

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

function getElapsedTime(startTime) {
  const elapsed = Date.now() - startTime;
  const seconds = Math.floor(elapsed / 1000);
  const minutes = Math.floor(seconds / 60);
  if (minutes > 0) {
    return `${minutes}m ${seconds % 60}s`;
  }
  return `${seconds}s`;
}

async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function generateBuildId() {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substring(2, 8);
  return `build-${timestamp}-${random}`;
}

// ============================================================================
// Stage Runner
// ============================================================================

async function runStage(name, fn) {
  logStage(name);
  const stageStart = Date.now();
  pipelineState.currentStage = name;

  const stageInfo = {
    name,
    startTime: stageStart,
    status: 'running',
    duration: null,
  };
  pipelineState.stages.push(stageInfo);

  try {
    await fn();
    stageInfo.status = 'success';
    stageInfo.duration = Date.now() - stageStart;
    logSuccess(`Stage "${name}" completed in ${getElapsedTime(stageStart)}`);
  } catch (error) {
    stageInfo.status = 'failed';
    stageInfo.duration = Date.now() - stageStart;
    logError(`Stage "${name}" failed after ${getElapsedTime(stageStart)}`);
    logError(`Error: ${error.message}`);
    pipelineState.errors.push({ stage: name, error: error.message });
    throw error;
  }
}

