async function stagePreFlight() {
  logInfo('Running pre-flight checks...');

  // Check Node.js version
  const nodeVersion = process.version;
  logInfo(`Node.js version: ${nodeVersion}`);

  // Check npm/yarn/pnpm availability
  const packageManager = detectPackageManager();
  logInfo(`Package manager: ${packageManager}`);

  // Get git info
  pipelineState.gitCommit = execSilent('git rev-parse --short HEAD') || 'unknown';
  pipelineState.gitBranch = execSilent('git rev-parse --abbrev-ref HEAD') || 'unknown';
  const gitAuthor = execSilent('git log -1 --pretty=format:"%an"') || 'unknown';
  const gitMessage = execSilent('git log -1 --pretty=format:"%s"') || 'unknown';

  logInfo(`Git branch: ${pipelineState.gitBranch}`);
  logInfo(`Git commit: ${pipelineState.gitCommit}`);
  logInfo(`Git author: ${gitAuthor}`);
  logInfo(`Git message: ${gitMessage}`);

  // Get package version
  const packageJson = readJson('package.json');
  if (packageJson) {
    pipelineState.version = packageJson.version;
    logInfo(`Package version: ${pipelineState.version}`);
  }

  // Check required environment variables based on deploy target
  if (CONFIG.deployTarget === 'remote') {
    if (!CONFIG.remoteHost || CONFIG.remoteHost === 'deploy@production-server.com') {
      logWarning('DEPLOY_HOST is not configured for remote deployment');
    }
  }

  // Check disk space
  if (process.platform !== 'win32') {
    const diskSpace = execSilent("df -h . | tail -1 | awk '{print $4}'");
    logInfo(`Available disk space: ${diskSpace}`);
  }

  // Generate build ID
  const buildId = generateBuildId();
  logInfo(`Build ID: ${buildId}`);
  process.env.BUILD_ID = buildId;

  logSuccess('Pre-flight checks passed');
}

function detectPackageManager() {
  if (fileExists('pnpm-lock.yaml')) return 'pnpm';
  if (fileExists('yarn.lock')) return 'yarn';
  if (fileExists('bun.lockb')) return 'bun';
  return 'npm';
}

function getInstallCommand(pm) {
  const commands = {
    npm: 'npm ci --prefer-offline --no-audit --no-fund',
    yarn: 'yarn install --frozen-lockfile --non-interactive',
    pnpm: 'pnpm install --frozen-lockfile',
    bun: 'bun install --frozen-lockfile',
  };
  return commands[pm] || commands.npm;
}

function getRunCommand(pm, script) {
  const commands = {
    npm: `npm run ${script}`,
    yarn: `yarn ${script}`,
    pnpm: `pnpm ${script}`,
    bun: `bun run ${script}`,
  };
  return commands[pm] || commands.npm;
}

async function stageInstallDependencies() {
  const pm = detectPackageManager();
  
  // Check cache for faster installs
  if (CONFIG.enableCache) {
    logInfo('Checking dependency cache...');
    const lockFile = {
      npm: 'package-lock.json',
      yarn: 'yarn.lock',
      pnpm: 'pnpm-lock.yaml',
      bun: 'bun.lockb',
    }[pm];
    
    if (fileExists(lockFile)) {
      const lockHash = execSilent(`md5sum ${lockFile} 2>/dev/null || md5 -q ${lockFile} 2>/dev/null`);
      if (lockHash) {
        logInfo(`Lock file hash: ${lockHash.split(' ')[0]}`);
      }
    }
  }

  // Install production + dev dependencies
  logInfo(`Installing dependencies with ${pm}...`);
  exec(getInstallCommand(pm), { retries: 2 });

  // Verify node_modules
  if (!fileExists('node_modules')) {
    throw new Error('node_modules directory was not created');
  }

  // Audit check (non-blocking)
  if (pm === 'npm') {
    logInfo('Running security audit...');
    const auditResult = execSilent('npm audit --production --json 2>/dev/null');
    if (auditResult) {
      try {
        const audit = JSON.parse(auditResult);
        const vulns = audit.metadata?.vulnerabilities || {};
        const critical = (vulns.critical || 0) + (vulns.high || 0);
        if (critical > 0) {
          logWarning(`Found ${critical} critical/high vulnerabilities. Run 'npm audit' for details.`);
        } else {
          logSuccess('No critical vulnerabilities found');
        }
      } catch {
        // Ignore parse errors
      }
    }
  }

  logSuccess('Dependencies installed successfully');
}

async function stageLinting() {
  const pm = detectPackageManager();
  const packageJson = readJson('package.json');
  
  if (!packageJson?.scripts) {
    logWarning('No scripts found in package.json, skipping lint');
    return;
  }

  const lintTasks = [];

  // ESLint
  if (packageJson.scripts.lint) {
    lintTasks.push({ name: 'ESLint', command: getRunCommand(pm, 'lint') });
  }

  // TypeScript type checking
  if (packageJson.scripts['type-check'] || packageJson.scripts.typecheck) {
    const script = packageJson.scripts['type-check'] ? 'type-check' : 'typecheck';
    lintTasks.push({ name: 'TypeScript', command: getRunCommand(pm, script) });
  } else if (fileExists('tsconfig.json') && (packageJson.devDependencies?.typescript || packageJson.dependencies?.typescript)) {
    lintTasks.push({ name: 'TypeScript', command: 'npx tsc --noEmit' });
  }

  // Prettier check
  if (packageJson.scripts['format:check'] || packageJson.scripts['prettier:check']) {
    const script = packageJson.scripts['format:check'] ? 'format:check' : 'prettier:check';
    lintTasks.push({ name: 'Prettier', command: getRunCommand(pm, script) });
  }

  if (lintTasks.length === 0) {
    logWarning('No lint tasks found, skipping');
    return;
  }

  // Run lint tasks (can be parallelized for speed)
  for (const task of lintTasks) {
    logInfo(`Running ${task.name}...`);
    try {
      exec(task.command);
      logSuccess(`${task.name} passed`);
    } catch (error) {
      throw new Error(`${task.name} failed: ${error.message}`);
    }
  }
}

async function stageRunTests() {
  const pm = detectPackageManager();
  const packageJson = readJson('package.json');

  if (!packageJson?.scripts?.test) {
    logWarning('No test script found in package.json, skipping tests');
    return;
  }

  // Set test environment variables
  const testEnv = {
    NODE_ENV: 'test',
    CI: 'true',
    JEST_JUNIT_OUTPUT_DIR: './test-results',
    JEST_JUNIT_OUTPUT_NAME: 'junit.xml',
  };

  Object.entries(testEnv).forEach(([key, value]) => {
    process.env[key] = value;
  });

  // Ensure test results directory
  ensureDir('./test-results');

  // Run tests with coverage
  logInfo('Running tests...');
  const testCommand = packageJson.scripts['test:ci']
    ? getRunCommand(pm, 'test:ci')
    : packageJson.scripts['test:coverage']
      ? getRunCommand(pm, 'test:coverage')
      : `${getRunCommand(pm, 'test')} -- --coverage --forceExit --detectOpenHandles --maxWorkers=50%`;

  try {
    exec(testCommand, {
      env: {
        ...process.env,
        ...testEnv,
      },
    });
  } catch (error) {
    // Check for test results even if tests failed
    if (fileExists('./test-results/junit.xml')) {
      logInfo('Test results saved to ./test-results/junit.xml');
    }
    throw new Error(`Tests failed: ${error.message}`);
  }

  // Report coverage summary
  if (fileExists('./coverage/coverage-summary.json')) {
    try {
      const coverageSummary = readJson('./coverage/coverage-summary.json');
      const total = coverageSummary.total;
      logInfo('Coverage Summary:');
      logInfo(`  Statements: ${total.statements.pct}%`);
      logInfo(`  Branches:   ${total.branches.pct}%`);
      logInfo(`  Functions:  ${total.functions.pct}%`);
      logInfo(`  Lines:      ${total.lines.pct}%`);

      // Enforce minimum coverage
      const minCoverage = parseInt(process.env.MIN_COVERAGE || '0', 10);
      if (minCoverage > 0 && total.lines.pct < minCoverage) {
        throw new Error(`Code coverage ${total.lines.pct}% is below minimum ${minCoverage}%`);
      }
    } catch (e) {
      if (e.message.includes('below minimum')) throw e;
      logWarning('Could not parse coverage summary');
    }
  }

  logSuccess('All tests passed');
}

async function stageBuild() {
  const pm = detectPackageManager();
  const packageJson = readJson('package.json');

  // Set production environment
  process.env.NODE_ENV = 'production';

  if (!packageJson?.scripts?.build) {
    logWarning('No build script found in package.json');
    
    // Check if there is a TypeScript config that needs compilation
    if (fileExists('tsconfig.json')) {
      logInfo('Found tsconfig.json, running tsc...');
      exec('npx tsc');
    } else {
      logInfo('No build step required');
      return;
    }
  } else {
    logInfo('Building application...');
    exec(getRunCommand(pm, 'build'));
  }

  // Verify build output exists
  const buildDir = CONFIG.buildDir;
  if (!fileExists(buildDir)) {
    // Check common build directories
    const commonDirs = ['dist', 'build', 'out', '.next', '.output'];
    const found = commonDirs.find(dir => fileExists(dir));
    if (found) {
      logInfo(`Build output found in: ${found}`);
    } else {
      logWarning('No build output directory found');
    }
  } else {
    // Get build size info
    if (process.platform !== 'win32') {
      const buildSize = execSilent(`du -sh ${buildDir} 2>/dev/null`);
      if (buildSize) {
        logInfo(`Build size: ${buildSize.split('\t')[0]}`);
      }
    }
  }

  // Create build metadata
  const buildMeta = {
    buildId: process.env.BUILD_ID,
    version: pipelineState.version,
    commit: pipelineState.gitCommit,
    branch: pipelineState.gitBranch,
    timestamp: new Date().toISOString(),
    nodeVersion: process.version,
    environment: CONFIG.environment,
  };

  writeJson(path.join(buildDir || '.', 'build-meta.json'), buildMeta);
  logInfo('Build metadata written');

  logSuccess('Build completed successfully');
}

async function stageCreateArtifact() {
  const buildDir = CONFIG.buildDir;
  const artifactName = `deploy-${pipelineState.gitCommit}-${Date.now()}.tar.gz`;
  const artifactPath = path.join(CONFIG.cacheDir, artifactName);

  ensureDir(CONFIG.cacheDir);

  // Determine what to include in the artifact
  const includeItems = [];
  
  if (fileExists(buildDir)) includeItems.push(buildDir);
  if (fileExists('package.json')) includeItems.push('package.json');
  if (fileExists('package-lock.json')) includeItems.push('package-lock.json');
  if (fileExists('yarn.lock')) includeItems.push('yarn.lock');
  if (fileExists('pnpm-lock.yaml')) includeItems.push('pnpm-lock.yaml');
  if (fileExists('.env.production')) includeItems.push('.env.production');
  if (fileExists('ecosystem.config.js')) includeItems.push('ecosystem.config.js');
  if (fileExists('Dockerfile')) includeItems.push('Dockerfile');
  if (fileExists('docker-compose.yml')) includeItems.push('docker-compose.yml');
  if (fileExists('docker-compose.production.yml')) includeItems.push('docker-compose.production.yml');

  // Add server files if they exist
  const serverFiles = ['server.js', 'server.ts', 'app.js', 'app.ts', 'index.js', 'index.ts', 'main.js', 'main.ts'];
  serverFiles.forEach(f => {
    if (fileExists(f)) includeItems.push(f);
  });

  // Add config directories
  const configDirs = ['config', 'migrations', 'seeds', 'scripts', 'public', 'views', 'templates'];
  configDirs.forEach(d => {
    if (fileExists(d)) includeItems.push(d);
  });

  if (includeItems.length === 0) {
    logWarning('No items to include in artifact');
    return;
  }

  logInfo(`Creating deployment artifact: ${artifactName}`);
  logInfo(`Including: ${includeItems.join(', ')}`);

  // Create tarball
  exec(`tar -czf ${artifactPath} ${includeItems.join(' ')} --exclude='*.map' --exclude='*.test.*' --exclude='*.spec.*' --exclude='__tests__' --exclude='__mocks__'`);

  // Get artifact size
  if (process.platform !== 'win32') {
    const size = execSilent(`ls -lh ${artifactPath} | awk '{print $5}'`);
    logInfo(`Artifact size: ${size}`);
  }

  pipelineState.artifactPath = artifactPath;
  logSuccess(`Artifact created: ${artifactPath}`);
}

async function stageDeploy() {
  const target = CONFIG.deployTarget;
  logInfo(`Deploying to: ${target} (${CONFIG.environment})`);

  switch (target) {
    case 'remote':
      await deployRemote();
      break;
    case 'docker':
      await deployDocker();
      break;
    case 'aws':
      await deployAWS();
      break;
    case 'local':
      await deployLocal();
      break;
    default:
      throw new Error(`Unknown deploy target: ${target}`);
  }

  logSuccess('Deployment completed successfully');
}

async function deployRemote() {
  const { remoteHost, remotePath, keepReleases, enableRollback } = CONFIG;
  const artifactPath = pipelineState.artifactPath;

  if (!artifactPath) {
    throw new Error('No artifact path found. Did the artifact creation stage run?');
  }

  const timestamp = Date.now();
  const releaseDir = `${remotePath}/releases/${timestamp}`;
  const currentLink = `${remotePath}/current`;
  const sharedDir = `${remotePath}/shared`;

  logInfo(`Deploying to ${remoteHost}:${remotePath}`);

  // Create directory structure on remote
  exec(`ssh ${remoteHost} "mkdir -p ${releaseDir} ${sharedDir}/node_modules ${sharedDir}/logs"`);

  // Upload artifact
  logInfo('Uploading artifact...');
  exec(`scp ${artifactPath} ${remoteHost}:${releaseDir}/deploy.tar.gz`);

  // Extract and setup on remote
  logInfo('Extracting and setting up...');
  const remoteCommands = [
    `cd ${releaseDir}`,
    `tar -xzf deploy.tar.gz`,
    `rm deploy.tar.gz`,
    // Symlink shared directories
    `ln -nfs ${sharedDir}/node_modules ${releaseDir}/node_modules`,
    `ln -nfs ${sharedDir}/logs ${releaseDir}/logs`,
    // Symlink .env if exists
    `[ -f ${sharedDir}/.env ] && ln -nfs ${sharedDir}/.env ${releaseDir}/.env || true`,
    // Install production dependencies
    `cd ${releaseDir} && npm ci --production --prefer-offline 2>/dev/null || npm install --production`,
    // Run migrations if script exists
    `cd ${releaseDir} && [ -f package.json ] && node -e "const p=require('./package.json'); if(p.scripts && p.scripts['migrate:production']) process.exit(0); else process.exit(1);" 2>/dev/null && npm run migrate:production || true`,
    // Switch symlink to new release
    `ln -nfs ${releaseDir} ${currentLink}`,
    // Restart application
    `cd ${currentLink} && (pm2 restart ecosystem.config.js --env production 2>/dev/null || pm2 restart all 2>/dev/null || (pm2 delete all 2>/dev/null; pm2 start ecosystem.config.js --env production 2>/dev/null) || echo "PM2 restart skipped - configure process manager")`,
  ].join(' && ');

  exec(`ssh ${remoteHost} '${remoteCommands}'`);

  // Clean old releases
  if (enableRollback && keepReleases > 0) {
    logInfo(`Keeping ${keepReleases} releases for rollback...`);
    exec(`ssh ${remoteHost} "cd ${remotePath}/releases && ls -1tr | head -n -${keepReleases} | xargs rm -rf 2>/dev/null || true"`, { ignoreError: true });
  }
}

async function deployDocker() {
  const { dockerRegistry, dockerImage, dockerTag } = CONFIG;
  const fullTag = `${dockerRegistry}/${dockerImage}:${dockerTag}`;
  const commitTag = `${dockerRegistry}/${dockerImage}:${pipelineState.gitCommit}`;

  // Build Docker image
  logInfo('Building Docker image...');
  
  // Use BuildKit for faster builds
  process.env.DOCKER_BUILDKIT = '1';
  
  const buildArgs = [
    `--build-arg NODE_ENV=production`,
    `--build-arg BUILD_ID=${process.env.BUILD_ID}`,
    `--build-arg GIT_COMMIT=${pipelineState.gitCommit}`,
    `--build-arg VERSION=${pipelineState.version || 'unknown'}`,
  ].join(' ');

  exec(`docker build ${buildArgs} -t ${fullTag} -t ${commitTag} .`);

  // Run container tests
  logInfo('Running container health check...');
  exec(`docker run --rm ${fullTag} node -e "console.log('Container OK')"`, { ignoreError: true });

  // Push to registry
  logInfo(`Pushing to ${dockerRegistry}...`);
  exec(`docker push ${fullTag}`);
  exec(`docker push ${commitTag}`);

  // Deploy based on orchestrator
  if (fileExists('docker-compose.production.yml')) {
    logInfo('Deploying with docker-compose...');
    exec(`docker-compose -f docker-compose.production.yml pull`);
    exec(`docker-compose -f docker-compose.production.yml up -d --remove-orphans`);
  } else if (execSilent('which kubectl')) {
    logInfo('Deploying to Kubernetes...');
    exec(`kubectl set image deployment/${dockerImage} ${dockerImage}=${commitTag}`, { ignoreError: true });
    exec(`kubectl rollout status deployment/${dockerImage} --timeout=300s`, { ignoreError: true });
  }

  // Cleanup old images
  exec(`docker image prune -f --filter "until=24h"`, { ignoreError: true });

  logInfo(`Image: ${fullTag}`);
  logInfo(`Image: ${commitTag}`);
}

async function deployAWS() {
  const { awsRegion, awsS3Bucket, awsEbEnvironment } = CONFIG;
  const artifactPath = pipelineState.artifactPath;

  if (!artifactPath) {
    throw new Error('No artifact path found');
  }

  // Check AWS CLI
  exec('aws --version', { silent: true });

  const s3Key = `deployments/${pipelineState.gitCommit}/${path.basename(artifactPath)}`;

  // Upload to S3
  logInfo(`Uploading to s3://${awsS3Bucket}/${s3Key}...`);
  exec(`aws s3 cp ${artifactPath} s3://${awsS3Bucket}/${s3Key} --region ${awsRegion}`);

  // Deploy to Elastic Beanstalk if configured
  if (awsEbEnvironment && awsEbEnvironment !== 'my-app-production') {
    const versionLabel = `v${pipelineState.version}-${pipelineState.gitCommit}`;
    
    logInfo(`Creating EB application version: ${versionLabel}`);
    exec(`aws elasticbeanstalk create-application-version \
      --region ${awsRegion} \
      --application-name ${CONFIG.dockerImage || 'myapp'} \
      --version-label "${versionLabel}" \
      --source-bundle S3Bucket="${awsS3Bucket}",S3Key="${s3Key}"`);

    logInfo(`Updating EB environment: ${awsEbEnvironment}`);
    exec(`aws elasticbeanstalk update-environment \
      --region ${awsRegion} \
      --environment-name ${awsEbEnvironment} \
      --version-label "${versionLabel}"`);

    // Wait for deployment
    logInfo('Waiting for deployment to complete...');
    exec(`aws elasticbeanstalk wait environment-updated \
      --region ${awsRegion} \
      --environment-name ${awsEbEnvironment}`, { ignoreError: true });
  }
}

async function deployLocal() {
  const pm = detectPackageManager();
  
  logInfo('Deploying locally...');

  // Stop existing process
  exec('pm2 stop all 2>/dev/null || true', { ignoreError: true, silent: true });

  // Install production dependencies
  if (pm === 'npm') {
    exec('npm ci --production --prefer-offline --no-audit', { ignoreError: true });
  }

  // Start with PM2 or directly
  if (fileExists('ecosystem.config.js')) {
    exec('pm2 start ecosystem.config.js --env production');
  } else {
    const packageJson = readJson('package.json');
    const startScript = packageJson?.scripts?.start || 'node server.js';
    exec(`pm2 start "${startScript}" --name app -i max --env production`, { ignoreError: true });
  }

  exec('pm2 save', { ignoreError: true });
}

async function stageHealthCheck() {
  const { healthCheckUrl, healthCheckRetries, healthCheckInterval } = CONFIG;
  
  logInfo(`Health check URL: ${healthCheckUrl}`);
  logInfo(`Max retries: ${healthCheckRetries}`);

  for (let attempt = 1; attempt <= healthCheckRetries; attempt++) {
    logInfo(`Health check attempt ${attempt}/${healthCheckRetries}...`);
    
    try {
      // Use curl or Node.js http
      const curlAvailable = execSilent('which curl');
      
      if (curlAvailable) {
        const result = execSilent(`curl -sf -o /dev/null -w "%{http_code}" --max-time 10 ${healthCheckUrl}`);
        if (result && parseInt(result) >= 200 && parseInt(result) < 400) {
          logSuccess(`Health check passed (HTTP ${result})`);
          return;
        }
        logWarning(`Health check returned HTTP ${result || 'timeout'}`);
      } else {
        // Use Node.js built-in http
        const http = require(healthCheckUrl.startsWith('https') ? 'https' : 'http');
        const statusCode = await new Promise((resolve, reject) => {
          const req = http.get(healthCheckUrl, { timeout: 10000 }, (res) => {
            resolve(res.statusCode);
          });
          req.on('error', reject);
          req.on('timeout', () => { req.destroy(); reject(new Error('timeout')); });
        });
        
        if (statusCode >= 200 && statusCode < 400) {
          logSuccess(`Health check passed (HTTP ${statusCode})`);
          return;
        }
        logWarning(`Health check returned HTTP ${statusCode}`);
      }
    } catch (error) {
      logWarning(`Health check failed: ${error.message}`);
    }

    if (attempt < healthCheckRetries) {
      logInfo(`Waiting ${healthCheckInterval / 1000}s before next attempt...`);
      await sleep(healthCheckInterval);
    }
  }

  throw new Error(`Health check failed after ${healthCheckRetries} attempts`);
}

async function stageCleanup() {
  logInfo('Running cleanup...');

  // Clean build cache
  if (fileExists('.cache')) {
    logInfo('Cleaning .cache directory');
  }

  // Clean old artifacts
  if (CONFIG.enableCache && fs.existsSync(CONFIG.cacheDir)) {
    const files = fs.readdirSync(CONFIG.cacheDir);
    const maxAge = 7 * 24 * 60 * 60 * 1000; // 7 days
    let cleaned = 0;

    files.forEach(file => {
      const filePath = path.join(CONFIG.cacheDir, file);
      try {
        const stat = fs.statSync(filePath);
        if (Date.now() - stat.mtimeMs > maxAge) {
          fs.unlinkSync(filePath);
          cleaned++;
        }
      } catch {
        // Ignore
      }
    });

    if (cleaned > 0) {
      logInfo(`Cleaned ${cleaned} old artifact(s)`);
    }
  }

  logSuccess('Cleanup completed');
}

// ============================================================================
// Notifications
// ============================================================================

async function sendNotification(status) {
  if (!CONFIG.slackWebhook) return;
  if (status === 'success' && !CONFIG.notifyOnSuccess) return;
  if (status === 'failure' && !CONFIG.notifyOnFailure) return;

  const emoji = status === 'success' ? '✅' : '❌';
  const color = status === 'success' ? '#36a64f' : '#ff0000';
  const totalTime = getElapsedTime(pipelineState.startTime);

  const stageList = pipelineState.stages
    .map(s => {
      const icon = s.status === 'success' ? '✅' : s.status === 'failed' ? '❌' : '⏳';
      const duration = s.duration ? getElapsedTime(s.startTime) : 'N/A';
      return `${icon} ${s.name} (${duration})`;
    })
    .join('\n');

  const payload = {
    attachments: [{
      color,
      title: `${emoji} Deployment ${status.toUpperCase()}: ${pipelineState.version || 'unknown'}`,
      fields: [
        { title: 'Environment', value: CONFIG.environment, short: true },
        { title: 'Branch', value: pipelineState.gitBranch, short: true },
        { title: 'Commit', value: pipelineState.gitCommit, short: true },
        { title: 'Total Time', value: totalTime, short: true },
        { title: 'Stages', value: stageList, short: false },
      ],
      footer: `Build ID: ${process.env.BUILD_ID}`,
      ts: Math.floor(Date.now() / 1000),
    }],
  };

  if (pipelineState.errors.length > 0) {
    payload.attachments[0].fields.push({
      title: 'Errors',
      value: pipelineState.errors.map(e => `• ${e.stage}: ${e.error}`).join('\n'),
      short: false,
    });
  }

  try {
    const curlAvailable = execSilent('which curl');
    if (curlAvailable) {
      exec(`curl -sf -X POST -H 'Content-type: application/json' --data '${JSON.stringify(payload)}' ${CONFIG.slackWebhook}`, { silent: true });
    } else {
      const https = require('https');
      const url = new URL(CONFIG.slackWebhook);
      const data = JSON.stringify(payload);
      
      await new Promise((resolve, reject) => {
        const req = https.request({
          hostname: url.hostname,
          path: url.pathname,
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Content-Length': data.length },
        }, resolve);
        req.on('error', reject);
        req.write(data);
        req.end();
      });
    }
    logInfo('Notification sent');
  } catch (error) {
    logWarning(`Failed to send notification: ${error.message}`);
  }
}

// ============================================================================
// Rollback Function
// ============================================================================

async function rollback() {
  logStage('ROLLBACK');

  if (CONFIG.deployTarget === 'remote') {
    const { remoteHost, remotePath } = CONFIG;
    logInfo('Rolling back to previous release...');
    
    const prevRelease = execSilent(
      `ssh ${remoteHost} "ls -1t ${remotePath}/releases | sed -n '2p'"`
    );
    
    if (prevRelease) {
      exec(`ssh ${remoteHost} "ln -nfs ${remotePath}/releases/${prevRelease} ${remotePath}/current && cd ${remotePath}/current && pm2 restart all"`);
      logSuccess(`Rolled back to release: ${prevRelease}`);
    } else {
      logError('No previous release found for rollback');
    }
  } else if (CONFIG.deployTarget === 'docker') {
    logInfo('Rolling back Docker deployment...');
    exec('docker-compose -f docker-compose.production.yml rollback 2>/dev/null || true', { ignoreError: true });
  } else if (CONFIG.deployTarget === 'aws') {
    logInfo('AWS rollback should be handled through Elastic Beanstalk console or CLI');
  }
}

// ============================================================================
// Pipeline Report
// ============================================================================

function printPipelineReport(status) {
  const totalTime = getElapsedTime(pipelineState.startTime);

  console.log('');
  console.log(`${COLORS.bold}${'='.repeat(70)}${COLORS.reset}`);
  console.log(`${COLORS.bold}  PIPELINE REPORT${COLORS.reset}`);
  console.log(`${'='.repeat(70)}`);
  console.log('');
  
  console.log(`  Status:       ${status === 'success' ? `${COLORS.green}SUCCESS` : `${COLORS.red}FAILED`}${COLORS.reset}`);
  console.log(`  Environment:  ${CONFIG.environment}`);
  console.log(`  Deploy Target:${CONFIG.deployTarget}`);
  console.log(`  Version:      ${pipelineState.version || 'N/A'}`);
  console.log(`  Commit:       ${pipelineState.gitCommit}`);
  console.log(`  Branch:       ${pipelineState.gitBranch}`);
  console.log(`  Build ID:     ${process.env.BUILD_ID || 'N/A'}`);
  console.log(`  Total Time:   ${totalTime}`);
  console.log('');

  console.log('  Stages:');
  pipelineState.stages.forEach(stage => {
    const icon = stage.status === 'success' ? `${COLORS.green}✅` : stage.status === 'failed' ? `${COLORS.red}❌` : `${COLORS.yellow}⏳`;
    const duration = stage.duration ? getElapsedTime(stage.startTime) : 'N/A';
    console.log(`    ${icon} ${stage.name.padEnd(30)} ${duration}${COLORS.reset}`);
  });

  if (pipelineState.warnings.length > 0) {
    console.log('');
    console.log(`  ${COLORS.yellow}Warnings (${pipelineState.warnings.length}):${COLORS.reset}`);
    pipelineState.warnings.forEach(w => {
      console.log(`    ${COLORS.yellow}⚠️  ${w}${COLORS.reset}`);
    });
  }

  if (pipelineState.errors.length > 0) {
    console.log('');
    console.log(`  ${COLORS.red}Errors (${pipelineState.errors.length}):${COLORS.reset}`);
    pipelineState.errors.forEach(e => {
      console.log(`    ${COLORS.red}❌ [${e.stage}] ${e.error}${COLORS.reset}`);
    });
  }

  console.log('');
  console.log(`${'='.repeat(70)}`);
  console.log('');
}

// ============================================================================
// Main Pipeline Execution
// ============================================================================

async function runPipeline() {
  const args = process.argv.slice(2);
  const command = args[0] || 'deploy';

  // Handle special commands
  if (command === 'rollback') {
    await rollback();
    return;
  }

  if (command === 'help' || command === '--help') {
    console.log(`
Usage: node pipeline.js [command] [options]

Commands:
  deploy      Run full deployment pipeline (default)
  build       Build only (no deployment)
  test        Run tests only
  rollback    Rollback to previous release
  help        Show this help message

Environment Variables:
  DEPLOY_ENV          Target environment (default: production)
  DEPLOY_TARGET       Deploy method: remote, docker, aws, local (default: remote)
  DEPLOY_HOST         Remote host for SSH deployment
  DEPLOY_PATH         Remote path for deployment
  DOCKER_REGISTRY     Docker registry URL
  DOCKER_IMAGE        Docker image name
  DOCKER_TAG          Docker image tag (default: latest)
  AWS_REGION          AWS region
  AWS_S3_BUCKET       S3 bucket for deployments
  AWS_EB_ENV          Elastic Beanstalk environment name
  BUILD_DIR           Build output directory (default: dist)
  SLACK_WEBHOOK_URL   Slack webhook for notifications
  HEALTH_CHECK_URL    URL for post-deployment health check
  MIN_COVERAGE        Minimum code coverage percentage
  ENABLE_CACHE        Enable build caching (default: true)
  ENABLE_ROLLBACK     Enable rollback capability (default: true)
  KEEP_RELEASES       Number of releases to keep (default: 5)
`);
    return;
  }

  let pipelineStatus = 'success';

  try {
    console.log('');
    console.log(`${COLORS.bold}${COLORS.cyan}╔══════════════════════════════════════════════════════════════════════╗${COLORS.reset}`);
    console.log(`${COLORS.bold}${COLORS.cyan}║                    CI/CD DEPLOYMENT PIPELINE                        ║${COLORS.reset}`);
    console.log(`${COLORS.bold}${COLORS.cyan}║                                                                      ║${COLORS.reset}`);
    console.log(`${COLORS.bold}${COLORS.cyan}║  Environment: ${CONFIG.environment.padEnd(20)} Target: ${CONFIG.deployTarget.padEnd(18)}║${COLORS.reset}`);
    console.log(`${COLORS.bold}${COLORS.cyan}╚══════════════════════════════════════════════════════════════════════╝${COLORS.reset}`);
    console.log('');

    // Stage 1: Pre-flight checks
    await runStage('Pre-flight Checks', stagePreFlight);

    // Stage 2: Install dependencies
    await runStage('Install Dependencies', stageInstallDependencies);

    // Stage 3: Linting (skip for deploy-only)
    if (command !== 'deploy-only') {
      await runStage('Linting & Type Checking', stageLinting);
    }

    // Stage 4: Tests (skip for build-only)
    if (command !== 'build' && command !== 'deploy-only') {
      await runStage('Run Tests', stageRunTests);
    }

    if (command === 'test') {
      // Test-only mode, stop here
      pipelineStatus = 'success';
      return;
    }

    // Stage 5: Build
    await runStage('Build Application', stageBuild);

    if (command === 'build') {
      // Build-only mode, stop here
      pipelineStatus = 'success';
      return;
    }

    // Stage 6: Create deployment artifact
    await runStage('Create Artifact', stageCreateArtifact);

    // Stage 7: Deploy
    await runStage('Deploy', stageDeploy);

    // Stage 8: Health check
    try {
      await runStage('Health Check', stageHealthCheck);
    } catch (healthError) {
      logError('Health check failed! Initiating rollback...');
      if (CONFIG.enableRollback) {
        try {
          await rollback();
          logSuccess('Rollback completed');
        } catch (rollbackError) {
          logError(`Rollback failed: ${rollbackError.message}`);
        }
      }
      throw healthError;
    }

    // Stage 9: Cleanup
    await runStage('Cleanup', stageCleanup);

    pipelineStatus = 'success';

  } catch (error) {
    pipelineStatus = 'failure';
    logError(`Pipeline failed: ${error.message}`);
  } finally {
    // Print report
    printPipelineReport(pipelineStatus);

    // Send notification
    await sendNotification(pipelineStatus);

    // Exit with appropriate code
    if (pipelineStatus === 'failure') {
      process.exit(1);
    }
  }
}

// ============================================================================
// Entry Point
// ============================================================================

runPipeline().catch(error => {
  logError(`Unhandled error: ${error.message}`);
  console.error(error.stack);
  process.exit(1);
});